-- Migration: §5 treatment body rewrites + §5.10 six new treatment pages.
-- Audit: Uncover-SEO-Content-Audit-Edits.docx §5 and §5.10.
--
-- §5 — Adds text_section pageBlocks to 6 existing treatments (wrinkle-relaxer,
-- fillers, gfc-hair-restoration, laser-hair-removal-women,
-- laser-hair-removal-men, hair-transplant). Bumps the faqsEmbed block's
-- _order up by N to make room.
--
-- §5 meta updates — updates meta_title and meta_description on 9 treatments
-- with keyword-rich copy from the audit.
--
-- §5.10 — Inserts 6 new treatment pages: prp-hair, chemical-peel,
-- melasma-treatment, q-switch-laser, stretch-marks-removal,
-- dandruff-treatment. Each with name/slug/hero/meta/pricing/body blocks.
--
-- Humanized voice throughout. Safe to re-run: meta updates are idempotent
-- UPDATEs; text_section inserts use deterministic IDs (DELETE-before-INSERT);
-- new treatment inserts use INSERT...WHERE NOT EXISTS.

BEGIN;

-- =========================================================================
-- §5 meta_title + meta_description updates
-- =========================================================================

UPDATE cms.treatments SET
  meta_title = 'Botox Treatment in Delhi NCR — Wrinkle Relaxer Cost & Clinic | Uncover',
