UPDATE cms._treatments_v v
SET version_meta_title = t.meta_title, version_meta_description = t.meta_description
FROM cms.treatments t WHERE v.parent_id = t.id AND v.latest = true AND t.slug = 'laser-hair-removal-women';

UPDATE cms.treatments SET
  meta_title = 'Laser Hair Removal for Men in Delhi NCR — Chest, Back, Beard & Full Body | Uncover',
  meta_description = 'Dermatologist-led laser hair removal for men across Delhi, Gurgaon, Noida. Chest, back, beard shaping, shoulders, full body. Free consultation + AI skin analysis.'
WHERE slug = 'laser-hair-removal-men';

UPDATE cms._treatments_v v
SET version_meta_title = t.meta_title, version_meta_description = t.meta_description
FROM cms.treatments t WHERE v.parent_id = t.id AND v.latest = true AND t.slug = 'laser-hair-removal-men';

UPDATE cms.treatments SET
  meta_title = 'Hair Transplant in Delhi NCR — FUE, Dermatologist-Led | Uncover',
  meta_description = 'FUE hair transplant at Uncover — dermatologist-performed, starting ₹85,000 + GST. 90–95% graft survival. Delhi, Gurgaon, Noida.'
WHERE slug = 'hair-transplant';

UPDATE cms._treatments_v v
SET version_meta_title = t.meta_title, version_meta_description = t.meta_description
FROM cms.treatments t WHERE v.parent_id = t.id AND v.latest = true AND t.slug = 'hair-transplant';

UPDATE cms.treatments SET
  meta_title = 'Skin Boosters & Profhilo Treatment in Delhi NCR — Hydration Fillers | Uncover',
  meta_description = 'Dermatologist-led skin boosters and Profhilo treatment for glassy, hydrated skin. Starting ₹14,999. 8 clinics across Delhi, Gurgaon, Noida.'
