-- =========================================================================
-- §5 body rewrites (text_section pageBlock inserts)
-- =========================================================================

-- ===== /treatment/wrinkle-relaxer — 3 new text_sections =====
UPDATE cms.treatments_blocks_faqs_embed
SET _order = 10
WHERE _parent_id = (SELECT id FROM cms.treatments WHERE slug = 'wrinkle-relaxer')
  AND _order = 7;

DELETE FROM cms.treatments_blocks_text_section
WHERE id IN ('seo-phase2-wrinkle-relaxer-tx-1','seo-phase2-wrinkle-relaxer-tx-2','seo-phase2-wrinkle-relaxer-tx-3');
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-wrinkle-relaxer-tx-1', (SELECT id FROM cms.treatments WHERE slug='wrinkle-relaxer'), 7, 'pageBlocks', 'Botox Cost in Delhi, Gurgaon & Noida', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Botox (wrinkle relaxer) pricing at Uncover starts from ₹8,999 per area. Price depends on the product used, the area being treated, and how many units are needed — someone treating a strong glabella frown takes more product than a first-time forehead plan.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Indicative ranges we share at consultation:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Single area (forehead, glabella, or crow''s feet): ₹8,999–₹14,999", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Two areas combined: ₹16,999–₹22,999", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Full upper face (three areas): ₹24,999–₹32,999", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Jawline slimming (masseter): ₹18,999–₹28,999", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Lip flip: ₹4,999–₹7,999", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "We price by what you actually need — not a fixed package. If your first session only needs a light dose, you pay for the light dose. Conservative first-time protocols are the norm at Uncover — we''d rather ask you back at the 2-week review to add more than over-treat on day one.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-wrinkle-relaxer-tx-2', (SELECT id FROM cms.treatments WHERE slug='wrinkle-relaxer'), 8, 'pageBlocks', 'Jawline Botox — Masseter Reduction for V-Shape Definition', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Jawline botox (masseter reduction) is the single most-booked botox variant at Uncover for women in their 30s and 40s. Bulky masseter muscles — from stress, clenching, or genetics — give the lower face a boxier shape. Botox into the masseter muscle softens that over 4–6 weeks, producing a more defined V-shape.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Expect: 20–30 units per side. First session lasts 5–6 months because the masseter is a large muscle. After 2–3 sessions the muscle atrophies and you''ll need fewer units + longer gaps between sessions.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "This is also the first line for night-time teeth grinding. Patients often tell us the TMJ pain and morning headaches disappear within a few weeks — quality of life win that has nothing to do with aesthetics.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-wrinkle-relaxer-tx-3', (SELECT id FROM cms.treatments WHERE slug='wrinkle-relaxer'), 9, 'pageBlocks', 'Botox for Forehead Wrinkles, Frown Lines & Crow''s Feet', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The classical upper-face botox plan covers three dynamic zones — and doing them together gives a more balanced result than treating any one in isolation.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Forehead (frontalis)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Horizontal lines when you raise your eyebrows. Botox relaxes the frontalis muscle so the lines etch in more slowly. Dose here is conservative — over-treatment can flatten the brow and cause a ''heavy'' feel.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Frown lines (glabella)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The ''11'' lines between your brows. Usually the earliest-appearing dynamic wrinkles because we frown at screens all day. Botox into the corrugator and procerus muscles softens them completely within 7–14 days.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Crow''s feet (orbicularis oculi)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Lines that fan out from the outer eye when you smile. Low doses here — over-treatment can limit natural smile animation. Our protocol keeps the medial muscle functional so you still look like yourself.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Combined upper-face botox lasts 3–4 months. Consistent patients (every 4–5 months for 12–18 months) often need fewer units per visit because the muscles retrain.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

-- ===== /treatment/fillers — 4 new text_sections =====
UPDATE cms.treatments_blocks_faqs_embed
SET _order = 11
WHERE _parent_id = (SELECT id FROM cms.treatments WHERE slug = 'fillers')
  AND _order = 7;

DELETE FROM cms.treatments_blocks_text_section
WHERE id IN ('seo-phase2-fillers-tx-1','seo-phase2-fillers-tx-2','seo-phase2-fillers-tx-3','seo-phase2-fillers-tx-4');
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-fillers-tx-1', (SELECT id FROM cms.treatments WHERE slug='fillers'), 7, 'pageBlocks', 'Lip Fillers — Cost, Types & What to Expect', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Lip fillers at Uncover start from ₹14,999 for a 1ml hydration-focused filler and ₹29,999 for a volume or shape filler. What you actually need depends on your starting lip anatomy and what you''re asking for — more hydration and plumpness, or a deliberate shape change.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "We use hyaluronic-acid fillers exclusively for lips — they''re reversible with hyaluronidase if you change your mind, and they integrate with your natural tissue rather than sitting on top of it. The result looks natural because the filler is the same molecule your lips already produce, just in a higher concentration.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most first-time lip filler patients land in a place where friends notice you look refreshed but can''t quite say what changed. That''s the Uncover philosophy — refresh, don''t alter. We always under-fill on session one and ask you back at 2 weeks if you want more.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Lip fillers typically last 9–12 months. After 2–3 consistent sessions, many patients find the results hold longer because the tissue structure has been primed.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-fillers-tx-2', (SELECT id FROM cms.treatments WHERE slug='fillers'), 8, 'pageBlocks', 'Under-Eye & Tear Trough Fillers', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Tear trough filler is the most requested treatment at Uncover after lip filler. It targets the hollow under the eye that deepens with age — and can exist even in your 20s if you''ve inherited it. Done correctly, it makes the under-eye area look rested instead of hollowed or tired.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Tear trough is a technically demanding area. The filler sits close to the orbital bone and near the infraorbital vessel. This is one area we strongly recommend only seeing a dermatologist for — not a cosmetologist, not a salon. Complications are rare but serious when they happen.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Expect: 0.5ml–1ml per eye. Cost typically ₹14,999–₹24,999. Results last 9–18 months. Mild initial swelling for 48 hours is normal; final result settles at 2 weeks.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What tear trough filler can and can''t fix: it addresses volume loss and hollowing. It does not fix dark pigmentation under the eye — that''s a separate issue often treated with laser or topical prescriptions. We diagnose both at consultation.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-fillers-tx-3', (SELECT id FROM cms.treatments WHERE slug='fillers'), 9, 'pageBlocks', 'Cheek Fillers — Mid-Face Volume & Lift', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Cheek fillers do two things — they restore lost volume on the cheekbones (the main reason mid-face sags in your 40s), and they visually lift the lower face without needing a surgical facelift.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Starting point: ₹29,999 for 1ml. Most plans use 2–4ml total over one or two sessions, depending on how much volume restoration is needed. Results last 12–18 months.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "We place cheek filler deep on the bone (supraperiosteal) for lift, or in the subcutaneous layer for softer volume. Your dermatologist will recommend the right plane based on your anatomy — over-filled superficial cheeks are the classic ''done'' look we specifically avoid.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-fillers-tx-4', (SELECT id FROM cms.treatments WHERE slug='fillers'), 10, 'pageBlocks', 'Jawline & Chin Fillers — Definition Without Surgery', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Jawline filler defines the angle of the mandible and, in combination with chin filler, can sharpen the lower face meaningfully. This is a growing request for men as well as women — a defined jawline reads as fit and aligned, regardless of actual age.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Typical plan: 2–4ml combined across jawline + chin. Cost ₹45,000–₹85,000 depending on total volume. Results last 12–18 months.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "For patients wanting a more dramatic jawline shift, we often combine filler with masseter botox — the botox softens the sides of the jaw, and the filler defines the angle. Two complementary interventions, natural-looking composite result.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Non-surgical rhinoplasty (nose filler) is also available at Uncover. It corrects bumps, droopy tips, and mild asymmetry using the same reversible hyaluronic-acid fillers. Not a replacement for surgical rhinoplasty for major structural changes — but for refinement, it''s a lower-risk option.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

-- ===== /treatment/gfc-hair-restoration — 3 new text_sections =====
UPDATE cms.treatments_blocks_faqs_embed
SET _order = 10
WHERE _parent_id = (SELECT id FROM cms.treatments WHERE slug = 'gfc-hair-restoration')
  AND _order = 7;

DELETE FROM cms.treatments_blocks_text_section
WHERE id IN ('seo-phase2-gfc-hair-restoration-tx-1','seo-phase2-gfc-hair-restoration-tx-2','seo-phase2-gfc-hair-restoration-tx-3');
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-gfc-hair-restoration-tx-1', (SELECT id FROM cms.treatments WHERE slug='gfc-hair-restoration'), 7, 'pageBlocks', 'GFC vs PRP — Which Is Right for Your Hair Loss?', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "GFC and PRP both come from your own blood. They''re often advertised as the same thing — they''re not. The preparation is different, the concentration is different, and in our clinical experience, the results are different too.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "PRP (Platelet-Rich Plasma)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Single-spin preparation. Blood is drawn, spun once to separate plasma + platelets from red cells, then re-injected. Contains platelets plus growth factors plus some residual cellular debris. Proven track record over 15+ years of clinical use.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "GFC (Growth Factor Concentrate)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Double-process preparation. Blood is drawn, activated to release growth factors from the platelets, then spun a second time to isolate a pure, clear concentrate without red cells or debris. Higher concentration of growth factors per ml. Cleaner injection, less post-session discomfort.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Our clinical preference, by case", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "For early-stage thinning (Norwood 1–2 or Ludwig I), either works — the cost difference often drives the choice. For moderate or established thinning with visibly miniaturised follicles, we lean GFC because the purer concentrate signals follicle recovery more consistently. For post-partum shed, either is appropriate — starting early matters more than the exact product.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "GFC at Uncover starts from ₹5,399 per session. PRP is typically 20–30% lower per session. Both need 4–6 sessions in the loading phase, then maintenance every 3–4 months.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-gfc-hair-restoration-tx-2', (SELECT id FROM cms.treatments WHERE slug='gfc-hair-restoration'), 8, 'pageBlocks', 'What to Expect From a GFC Session at Uncover', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A GFC session at our clinic takes 45–60 minutes end-to-end. Here''s what actually happens:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Numbing cream applied to the scalp 30 minutes before", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Blood draw (10–15ml from your arm)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Blood processed through a double-spin + activator protocol (20 minutes)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Clear growth factor concentrate injected into the scalp in a planned grid pattern (15–20 minutes)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Mild redness and scalp tenderness for a day", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "No hair washing for 24 hours post-session", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "First visible result: session 3 for most patients, as signalled by reduced active shedding. Real density improvement shows at month 3 post-loading phase.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-gfc-hair-restoration-tx-3', (SELECT id FROM cms.treatments WHERE slug='gfc-hair-restoration'), 9, 'pageBlocks', 'Who GFC Works Best For', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "GFC produces the most consistent results in these profiles:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Early-to-moderate androgenic alopecia (Norwood 1–3, Ludwig I–II)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Post-partum telogen effluvium (accelerates return to baseline by 3–6 months)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Diffuse thinning in women with PCOS (alongside hormonal management)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Patients looking for an alternative to finasteride or minoxidil-only protocols", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Post-transplant patients wanting to improve graft density and speed", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Where GFC isn''t enough on its own: advanced baldness (Norwood 5+), scarring alopecia (needs dermatologist diagnosis first), or patients whose primary driver is nutritional — we treat the underlying deficiency first.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

-- ===== /treatment/laser-hair-removal-women — 3 new text_sections =====
UPDATE cms.treatments_blocks_faqs_embed
SET _order = 14
WHERE _parent_id = (SELECT id FROM cms.treatments WHERE slug = 'laser-hair-removal-women')
  AND _order = 11;

DELETE FROM cms.treatments_blocks_text_section
WHERE id IN ('seo-phase2-laser-hair-removal-women-tx-1','seo-phase2-laser-hair-removal-women-tx-2','seo-phase2-laser-hair-removal-women-tx-3');
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-laser-hair-removal-women-tx-1', (SELECT id FROM cms.treatments WHERE slug='laser-hair-removal-women'), 11, 'pageBlocks', 'Safe for Dark Skin & All Skin Tones — Nd:YAG 1064nm', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The laser wavelength matters more than the clinic name. At Uncover we use Nd:YAG 1064nm across all sessions — the safest wavelength for pigmented Indian skin (Fitzpatrick III–V, and VI with test spot first).", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Why the wavelength matters: 1064nm penetrates deeper and has lower affinity for melanin in the surrounding skin compared to shorter wavelengths (755nm alexandrite, 810nm diode). On darker skin, shorter wavelengths risk burns and post-inflammatory hyperpigmentation. Nd:YAG sidesteps that risk.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What this looks like in practice: a session on Fitzpatrick V skin at Uncover uses a different fluence than the same area on Fitzpatrick II — but both get the same laser. Your dermatologist titrates for your specific skin, not a generic clinic protocol.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "For Fitzpatrick VI patients, we always do a test spot on the planned treatment area 10 days before the first full session. If the test spot heals cleanly we proceed; if not we adjust the plan.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-laser-hair-removal-women-tx-2', (SELECT id FROM cms.treatments WHERE slug='laser-hair-removal-women'), 12, 'pageBlocks', 'Laser Hair Removal for Brides — 6-Month Pre-Wedding Protocol', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Bridal laser is one of our highest-volume consultations from September onwards (peak winter wedding prep season). The plan looks different from standard laser because the timeline is fixed and the areas are often more comprehensive.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Start 6–8 months before the wedding for a complete face + full body series", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Treatments spaced 4–6 weeks apart, typically 6–8 sessions total per area", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Final session 2 weeks before the wedding (no later, no earlier)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Strict SPF 50 between sessions — bridal trousseau trials and outdoor pre-wedding shoots require it", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "If you have less than 6 months, we plan a focused protocol: upper lip, underarms, and bikini take priority — the areas most visible in lehenga trials. We''d rather get great results on 3 areas than partial results on 8.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Our bridal package bundles LHR with HydraFacial (monthly), laser toning (for pigmentation), and one skin-polish treatment the week before. Itemised pricing at consultation — typical bridal plans run ₹60,000–₹1,50,000 over 6 months.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-laser-hair-removal-women-tx-3', (SELECT id FROM cms.treatments WHERE slug='laser-hair-removal-women'), 13, 'pageBlocks', 'Best Laser Hair Removal Clinic in Delhi, Gurgaon & Noida', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Uncover runs 8 clinics across Delhi NCR — four in Delhi (Greater Kailash, Lajpat Nagar, Preet Vihar, Punjabi Bagh), three in Gurgaon (Golf Course Road, Iris Broadway Sector 85, AIPL Joy Central Sector 65), and one in Noida (Sector 104). Every clinic runs the same laser device, the same protocol, and is staffed by board-certified dermatologists.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What to check before booking at any clinic (not just ours):", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The laser device name — Alma Soprano Titanium, Candela GentleMax Pro, or equivalent medical-grade", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Dermatologist-led delivery, not technician-led", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Nd:YAG 1064nm for pigmented skin (III–VI)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A test spot option for Fitzpatrick VI patients", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Transparent session count and pricing before you commit", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "If any of those are missing, look elsewhere — regardless of brand. Uncover is one option among several reputable dermatologist-led chains in Delhi NCR; we''d rather you pick the right fit than sign up without checking.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

-- ===== /treatment/laser-hair-removal-men — 3 new text_sections =====
UPDATE cms.treatments_blocks_faqs_embed
SET _order = 10
WHERE _parent_id = (SELECT id FROM cms.treatments WHERE slug = 'laser-hair-removal-men')
  AND _order = 7;

DELETE FROM cms.treatments_blocks_text_section
WHERE id IN ('seo-phase2-laser-hair-removal-men-tx-1','seo-phase2-laser-hair-removal-men-tx-2','seo-phase2-laser-hair-removal-men-tx-3');
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-laser-hair-removal-men-tx-1', (SELECT id FROM cms.treatments WHERE slug='laser-hair-removal-men'), 7, 'pageBlocks', 'Beard Laser Hair Removal & Beard Shaping', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Beard laser is one of the most-asked treatments by men in their 20s and 30s at Uncover. It splits into two different goals — and the plan depends on which goal you''re after.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Beard shaping (not removal)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most men want to clean up the neck and cheek lines without removing the beard itself. A few laser sessions on those specific zones give you a permanent clean line that no longer needs daily razor maintenance. You keep your beard, lose the neck-shave.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Full beard removal", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Men who want to permanently lose the beard entirely — whether for skin comfort, professional reasons, or personal preference. This is a full 8–10 session series on the beard zone. Ingrown hairs and razor bumps also resolve as a side benefit.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Either plan starts from ₹9,999 per session for targeted beard work. Your dermatologist will mark the exact zones on day one so you leave the consultation with a clear visual plan.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-laser-hair-removal-men-tx-2', (SELECT id FROM cms.treatments WHERE slug='laser-hair-removal-men'), 8, 'pageBlocks', 'Chest, Back & Full Body Laser for Men', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Chest and back laser for men is a larger-area treatment — the total skin surface is 3–4× what women typically treat. That affects session count and price.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Chest (pectoral + upper abdomen): 8–10 sessions, ₹4,999–₹8,999 per session", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Full back: 8–12 sessions, ₹5,999–₹10,999 per session", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Shoulders: 6–8 sessions, ₹2,999–₹5,999 per session", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Full body (chest, back, shoulders, arms, legs): packaged quote after consultation", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Men''s hair tends to be denser and coarser, which actually helps — the laser targets coarse, dark hair most efficiently. Many men see dramatic reduction by session 4. The full reduction plan is longer (8–10 sessions) because of the area size, not difficulty.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-laser-hair-removal-men-tx-3', (SELECT id FROM cms.treatments WHERE slug='laser-hair-removal-men'), 9, 'pageBlocks', 'Is Laser Hair Removal for Men Permanent?', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "For men the same principle applies as for women — ''permanent reduction'', not ''100% permanent removal''. The US FDA approves laser hair removal under that label because a complete series gives 70–90% reduction that holds long-term, with one maintenance session every 12–24 months catching any reactivated follicles.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "One factor specific to men: testosterone-driven follicles on chest, back, and shoulders can reactivate with age as hormone levels shift. Some men in their 40s notice a new patch of coarser hair on the chest 5–10 years after a full series. One targeted maintenance session handles it.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "If you''re committing to a full series as a man, budget for one maintenance session every 18–24 months for the rest of your life. Compared to daily shaving or monthly waxing, it''s still the cheapest hair-removal option long-term.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

-- ===== /treatment/hair-transplant — 3 new text_sections =====
UPDATE cms.treatments_blocks_faqs_embed
SET _order = 12
WHERE _parent_id = (SELECT id FROM cms.treatments WHERE slug = 'hair-transplant')
  AND _order = 9;

DELETE FROM cms.treatments_blocks_text_section
WHERE id IN ('seo-phase2-hair-transplant-tx-1','seo-phase2-hair-transplant-tx-2','seo-phase2-hair-transplant-tx-3');
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-hair-transplant-tx-1', (SELECT id FROM cms.treatments WHERE slug='hair-transplant'), 9, 'pageBlocks', 'FUE vs DHI — Which Technique Is Right for You?', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The two dominant hair transplant techniques are FUE (Follicular Unit Extraction) and DHI (Direct Hair Implantation). Both are minimally invasive, both preserve individual follicles, both produce permanent results. The difference is in the implantation step.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "FUE", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Follicles are extracted individually from the donor area, then implanted into pre-made recipient sites. The gold standard for most cases — it handles any graft count, scales to very large sessions, and has decades of clinical evidence.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "DHI", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Uses a Choi pen implanter that extracts and implants the follicle in a single action, without making recipient sites first. Allows denser packing in smaller session sizes. Slower per graft, so less efficient for large 3,000+ graft cases.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Our honest take", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "For 90% of patients, FUE is the right pick — the evidence base is stronger, the session scales to any graft count, and an experienced dermatologist can achieve excellent density. DHI has niche advantages for small, very dense restorations in specific areas — but it''s not automatically ''better'' despite how it''s sometimes marketed.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Uncover performs FUE because the consistency across graft counts matters more than the marginal density advantage DHI offers in small cases. If a patient''s needs genuinely fit DHI better, we refer.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-hair-transplant-tx-2', (SELECT id FROM cms.treatments WHERE slug='hair-transplant'), 10, 'pageBlocks', 'Hair Transplant Success Rate — What''s Realistic?', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Graft survival at reputable Indian clinics runs 90–95% for FUE. That''s the technical number. Whether a transplant counts as ''successful'' depends on three other things:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Density — does the transplanted area look full enough?", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Naturalness — does the hairline design fit your face?", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Durability — does it still look right at 10 and 20 years?", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Survival depends on surgical technique plus patient factors — smokers, diabetics, and anyone with compromised circulation see 5–10% lower survival. Density depends on donor density and how aggressively the transplant is planned. Naturalness depends entirely on the dermatologist''s aesthetic judgment on the hairline.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What makes transplants look ''off'': too-low hairlines, uniform density front-to-back (instead of graduated), wrong follicle angle, or single-hair grafts placed where multi-hair grafts belong. These are experience issues, not technology issues.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-hair-transplant-tx-3', (SELECT id FROM cms.treatments WHERE slug='hair-transplant'), 11, 'pageBlocks', 'Hair Transplant Cost in Delhi, Gurgaon & Noida', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "FUE hair transplant at Uncover starts from ₹85,000 + GST. Total cost scales with graft count:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Norwood 3 (frontal + mid scalp, 1,500–2,500 grafts): ₹85,000–₹1,75,000", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Norwood 4 (2,500–3,500 grafts): ₹1,75,000–₹2,50,000", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Norwood 5+ (3,500–5,000 grafts): ₹2,50,000–₹3,75,000", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Women''s frontal/temporal restoration (500–1,500 grafts): ₹60,000–₹1,25,000", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pricing is the same across our Delhi, Gurgaon, and Noida clinics — we don''t vary by location. What varies is who''s closer to you. Most transplant patients pick the clinic they can reach easily for follow-ups at months 1, 3, 6, and 12.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Every plan comes with a written graft count, clear hairline design mark-up, and itemised cost at consultation. No variable pricing or add-ons on the day of procedure.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

