-- ===== /treatment/prp-hair =====
INSERT INTO cms.treatments (
  name, slug,
  hero_headline, hero_tagline, hero_excerpt,
  details_target_areas, details_service_time, details_starting_price,
  details_sessions, details_downtime,
  meta_title, meta_description,
  _status, display_rank, display_show_in_header,
  created_at, updated_at
)
SELECT
  'PRP for Hair', 'prp-hair',
  'PRP Hair Treatment — Dermatologist-Led at Uncover', 'Platelet-Rich Plasma', 'PRP (Platelet-Rich Plasma) uses your own blood to stimulate hair regrowth. Dermatologist-led, US-FDA-recognised protocol, transparent pricing. 8 clinics across Delhi NCR.',
  'Scalp (frontal, crown, temples, vertex)', '45–60 minutes', '₹4,999',
  '4–6 loading + maintenance', 'None',
  'PRP Hair Treatment in Delhi NCR — Dermatologist-Led | Uncover', 'PRP hair treatment at Uncover starting ₹4,999 per session. Dermatologist-led Platelet-Rich Plasma for hair fall and thinning across Delhi, Gurgaon, Noida.',
  'published', 999, false,
  now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.treatments WHERE slug = 'prp-hair');

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-prp-hair-tx-1';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-prp-hair-tx-1', (SELECT id FROM cms.treatments WHERE slug='prp-hair'), 1, 'pageBlocks', 'What Is PRP Hair Treatment?', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "PRP — Platelet-Rich Plasma — is a regenerative hair-loss treatment that uses your own blood. We draw a small volume from your arm, spin it in a centrifuge to separate the platelet-rich layer, and inject that concentrate into your scalp in a planned grid. The platelets release growth factors that signal dormant follicles to re-enter the growth phase.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "PRP is not a new treatment — it''s been used clinically in dermatology and sports medicine for over 15 years, with strong evidence for early-to-moderate androgenic alopecia in both men and women. At Uncover every PRP session is performed by a board-certified dermatologist using the same sterile, single-spin protocol the published studies used.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-prp-hair-tx-2';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-prp-hair-tx-2', (SELECT id FROM cms.treatments WHERE slug='prp-hair'), 2, 'pageBlocks', 'Who Is PRP For?', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Early-stage male pattern hair loss (Norwood 1–3)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Female pattern hair loss (Ludwig I–II)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Post-partum telogen effluvium", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "PCOS-driven thinning (alongside hormonal management)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Diffuse thinning after illness, stress, or crash dieting", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Patients looking for an alternative to minoxidil or finasteride", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Where PRP is not enough on its own: advanced baldness (Norwood 5+, where transplant is indicated), scarring alopecia, or hair loss driven primarily by iron deficiency or thyroid disorder — we treat the underlying cause first.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-prp-hair-tx-3';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-prp-hair-tx-3', (SELECT id FROM cms.treatments WHERE slug='prp-hair'), 3, 'pageBlocks', 'PRP vs GFC — What''s the Difference?', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Both use your blood. PRP is single-spin — contains platelets, growth factors, and residual cellular debris. GFC (Growth Factor Concentrate) is double-processed — a purer, clearer concentrate of growth factors without the cellular debris. GFC is 20–30% more expensive per session but produces slightly faster visible regrowth in most patients.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "For early thinning either treatment works and the cost difference often drives the choice. For more established cases we lean GFC. Your dermatologist will recommend based on your specific hair loss pattern at the AI scalp analysis.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-prp-hair-tx-4';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-prp-hair-tx-4', (SELECT id FROM cms.treatments WHERE slug='prp-hair'), 4, 'pageBlocks', 'PRP Cost & Session Plan at Uncover', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "PRP at Uncover starts from ₹4,999 per session. A standard course is 4–6 sessions in the loading phase (one every 3–4 weeks), followed by maintenance sessions every 3–4 months.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Full 6-session loading plan: ₹24,999–₹34,999. Maintenance sessions at standard per-session pricing. Itemised plan shared at consultation — we don''t package-sell if the protocol your hair actually needs is shorter.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

-- ===== /treatment/chemical-peel =====
INSERT INTO cms.treatments (
  name, slug,
  hero_headline, hero_tagline, hero_excerpt,
  details_target_areas, details_service_time, details_starting_price,
  details_sessions, details_downtime,
  meta_title, meta_description,
  _status, display_rank, display_show_in_header,
  created_at, updated_at
)
SELECT
  'Chemical Peel Treatment', 'chemical-peel',
  'Chemical Peels at Uncover', 'Superficial to medium-depth, dermatologist-led', 'Dermatologist-led chemical peels for acne, pigmentation, texture, and anti-aging. Starting ₹3,000 per session. Safe depths for Indian skin across Fitzpatrick III–VI.',
  'Face, neck, back, hands', '30–45 minutes', '₹3,000',
  '4–6 typical', '1–7 days (depth-dependent)',
  'Chemical Peel Treatment in Delhi NCR — Dermatologist-Led | Uncover', 'Dermatologist-led chemical peels from ₹3,000. Safe depths for Indian skin. Acne, pigmentation, texture, anti-aging. 8 clinics Delhi, Gurgaon, Noida.',
  'published', 999, false,
  now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.treatments WHERE slug = 'chemical-peel');

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-chemical-peel-tx-1';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-chemical-peel-tx-1', (SELECT id FROM cms.treatments WHERE slug='chemical-peel'), 1, 'pageBlocks', 'What Is a Chemical Peel?', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A chemical peel applies a controlled acid (or mix of acids) to the skin to exfoliate the upper layers and trigger a structured regeneration. Done well it addresses pigmentation, acne, texture, fine lines, and enlarged pores. Done poorly — wrong depth for your skin type, wrong pre-treatment, wrong post-peel care — it causes pigmentation on Indian skin.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Every peel at Uncover is performed by a dermatologist after an AI skin analysis and Fitzpatrick type check. The peel depth and acid blend are tailored to your skin — not a one-size-fits-all protocol.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-chemical-peel-tx-2';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-chemical-peel-tx-2', (SELECT id FROM cms.treatments WHERE slug='chemical-peel'), 2, 'pageBlocks', 'Peel Depths & What They Treat', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Superficial peels (glycolic, salicylic, mandelic)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Exfoliation of the top epidermal layers. Treats mild acne, mild pigmentation, dull skin. 1–3 days of mild flaking post-session. 4–6 session series typical.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Medium peels (Jessner''s, 20–35% TCA)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Penetrates to the upper dermis. Treats moderate pigmentation, acne scarring, fine lines, actinic damage. 5–7 days of visible peeling. Indian skin needs 2–4 weeks of pre-treatment brightening before medium peels to reduce PIH risk.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Deep peels (phenol, high TCA)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Done infrequently and under medical supervision. Treats severe photo-damage, deep wrinkles, advanced pigmentation. 10–14 day recovery. Rarely used on Fitzpatrick IV–VI because of PIH risk.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-chemical-peel-tx-3';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-chemical-peel-tx-3', (SELECT id FROM cms.treatments WHERE slug='chemical-peel'), 3, 'pageBlocks', 'Peels We Use Most Often at Uncover', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Un-Tan Glow Peel — tranexamic acid blend for tan removal and brightening", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pigment Buster Peel — targets melasma and PIH on Indian skin", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Acne Buster Peel — salicylic-based for active acne and oily skin", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Anti-Scar Peel — combination formula for mild-to-moderate acne scarring", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Under-Eye Peel — mandelic-based, gentle for tear-trough pigmentation", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Black Peel — combination medium-depth for PIH and texture", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Your dermatologist will pick the right one based on your diagnosis — we don''t sell peel packages without matching them to your specific skin issue.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-chemical-peel-tx-4';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-chemical-peel-tx-4', (SELECT id FROM cms.treatments WHERE slug='chemical-peel'), 4, 'pageBlocks', 'Chemical Peel Cost in Delhi NCR', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Chemical peels at Uncover start from ₹3,000 per session for superficial peels. Medium-depth peels range ₹5,000–₹15,000 per session depending on the acid blend and area. Most patients do 4–6 sessions in a series spaced 3–4 weeks apart.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Packaged plans are quoted at consultation after the AI skin analysis. Home-care products (brightening serums, SPF, retinoids for nighttime) are essential for the result to hold — your dermatologist will build them into the plan.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

-- ===== /treatment/melasma-treatment =====
INSERT INTO cms.treatments (
  name, slug,
  hero_headline, hero_tagline, hero_excerpt,
  details_target_areas, details_service_time, details_starting_price,
  details_sessions, details_downtime,
  meta_title, meta_description,
  _status, display_rank, display_show_in_header,
  created_at, updated_at
)
SELECT
  'Melasma Treatment', 'melasma-treatment',
  'Melasma Treatment — Dermatologist-Led at Uncover', 'Q-switch laser, topicals, and the Indian-skin-specific protocol', 'Dermatologist-led melasma treatment for Indian skin. Q-switch laser toning, prescription topicals, and medical peels — tailored to reduce flares, not provoke them.',
  'Cheeks, forehead, upper lip, chin, neck', '30–45 minutes', '₹7,999',
  '6–10 laser toning + maintenance', 'Minimal — mild redness for 1–2 hours',
  'Melasma Treatment in Delhi NCR — Q-switch Laser & Topicals | Uncover', 'Dermatologist-led melasma treatment starting ₹7,999. Q-switch laser toning, prescription topicals, and medical peels safe for Indian skin. Uncover Delhi NCR.',
  'published', 999, false,
  now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.treatments WHERE slug = 'melasma-treatment');

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-melasma-treatment-tx-1';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-melasma-treatment-tx-1', (SELECT id FROM cms.treatments WHERE slug='melasma-treatment'), 1, 'pageBlocks', 'Why Melasma Needs a Different Plan', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Melasma is the most common pigmentation concern in Indian women — symmetrical patches on the cheeks, forehead, upper lip, and chin, often worsened by sun exposure and hormonal changes. It is genuinely chronic, which means we manage it, not ''cure'' it.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What makes melasma different from tan or post-inflammatory pigmentation is its reactivity. Aggressive laser, heat, and the wrong topicals actively make melasma worse. A plan that works is conservative, layered, and maintained long-term.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-melasma-treatment-tx-2';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-melasma-treatment-tx-2', (SELECT id FROM cms.treatments WHERE slug='melasma-treatment'), 2, 'pageBlocks', 'The Uncover Melasma Protocol', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Q-switch Nd:YAG laser toning — first-line treatment, 6–10 sessions spaced 2–3 weeks apart", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Prescription topicals — hydroquinone, tranexamic acid, or azelaic acid based on your response", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Medical peels — mandelic, lactic, or tranexamic acid blends between laser sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Strict SPF 50 daily — non-negotiable, indoors and out", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Trigger management — identifying and controlling heat, hormonal, and UV triggers", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Maintenance — one laser toning every 2–3 months + lifetime topical protocol", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most patients reduce melasma 70–90% with a structured plan and maintain that result. Flare-ups happen — pregnancy, unprotected summer, stress — and we handle them with a short tune-up rather than restarting from zero.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-melasma-treatment-tx-3';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-melasma-treatment-tx-3', (SELECT id FROM cms.treatments WHERE slug='melasma-treatment'), 3, 'pageBlocks', 'What Melasma Treatment Cannot Promise', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Permanent clearance in a set number of sessions — not possible. Any clinic promising ''melasma gone in 3 sessions'' is selling you a plan that will fail. Melasma responds to consistent, careful management, not one-shot interventions.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Single-layer treatment — topicals alone, or laser alone, rarely work. The plan that actually holds layers multiple interventions together over 6–12 months. Your dermatologist builds the sequence at consultation.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-melasma-treatment-tx-4';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-melasma-treatment-tx-4', (SELECT id FROM cms.treatments WHERE slug='melasma-treatment'), 4, 'pageBlocks', 'Cost & Session Plan', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Q-switch laser toning starts from ₹7,999 per session. A full melasma treatment plan — laser series + topical prescriptions + peels — typically runs ₹50,000–₹1,00,000 over the first 6 months, plus ongoing maintenance at ₹7,999–₹15,000 every 2–3 months.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Itemised cost after the AI skin analysis. We don''t recommend a plan blind.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

-- ===== /treatment/q-switch-laser =====
INSERT INTO cms.treatments (
  name, slug,
  hero_headline, hero_tagline, hero_excerpt,
  details_target_areas, details_service_time, details_starting_price,
  details_sessions, details_downtime,
  meta_title, meta_description,
  _status, display_rank, display_show_in_header,
  created_at, updated_at
)
SELECT
  'Q-switch Laser Treatment', 'q-switch-laser',
  'Q-switch Laser for Pigmentation & Tan', 'Nd:YAG 1064nm, safe for all Indian skin types', 'Q-switch Nd:YAG laser at Uncover — first-line treatment for melasma, PIH, sun spots, tan, and unwanted pigmentation on Indian skin. Dermatologist-led, starting ₹7,999.',
  'Face, neck, underarms, body, tattoo sites', '20–30 minutes', '₹7,999',
  '4–8 typical', 'Minimal',
  'Q-switch Laser Treatment in Delhi NCR — Pigmentation, Tan, PIH | Uncover', 'Dermatologist-led Q-switch Nd:YAG laser treatment starting ₹7,999. Safe for Indian skin types III–VI. Melasma, PIH, tan, sun spots. Uncover Delhi NCR.',
  'published', 999, false,
  now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.treatments WHERE slug = 'q-switch-laser');

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-q-switch-laser-tx-1';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-q-switch-laser-tx-1', (SELECT id FROM cms.treatments WHERE slug='q-switch-laser'), 1, 'pageBlocks', 'What Is a Q-switch Laser?', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A Q-switched laser delivers very short, high-intensity pulses of light — nanoseconds long. At that pulse duration the laser energy fragments pigment particles without heating the surrounding skin. On Indian skin (Fitzpatrick III–VI) this is the safest laser technology for pigmentation work.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The version we use at Uncover is Q-switched Nd:YAG 1064nm. That specific wavelength has low affinity for melanin in the top skin layers and high affinity for pigment in the deeper layers — exactly what pigmented skin needs to clear pigmentation safely.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-q-switch-laser-tx-2';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-q-switch-laser-tx-2', (SELECT id FROM cms.treatments WHERE slug='q-switch-laser'), 2, 'pageBlocks', 'What Q-switch Laser Treats', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Melasma — symmetrical cheek/forehead/upper lip patches", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "PIH (post-inflammatory hyperpigmentation) — dark marks from acne, injury, or friction", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Sun spots and age spots", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Freckles", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Tan removal", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Underarm pigmentation", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 7, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Areola and intimate-area pigmentation", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 8, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Tattoo removal (black ink responds best to 1064nm)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What Q-switch doesn''t treat: textural scarring (needs microneedling or fractional laser), deep wrinkles, or volume loss. If pigmentation is your primary concern and texture is secondary, Q-switch is the first intervention — we add others in sequence if needed.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-q-switch-laser-tx-3';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-q-switch-laser-tx-3', (SELECT id FROM cms.treatments WHERE slug='q-switch-laser'), 3, 'pageBlocks', 'Session Plan & Cost', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Q-switch laser at Uncover starts from ₹7,999 per session. Most pigmentation concerns clear in 4–6 sessions spaced 2–3 weeks apart. Melasma needs a longer 6–10 session plan plus maintenance. Tattoo removal takes longer — 8–15 sessions depending on ink type and age.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Every session is preceded by a test spot on new Fitzpatrick VI patients. Sessions take 20–30 minutes, minimal downtime, return to normal activities immediately.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

-- ===== /treatment/stretch-marks-removal =====
INSERT INTO cms.treatments (
  name, slug,
  hero_headline, hero_tagline, hero_excerpt,
  details_target_areas, details_service_time, details_starting_price,
  details_sessions, details_downtime,
  meta_title, meta_description,
  _status, display_rank, display_show_in_header,
  created_at, updated_at
)
SELECT
  'Stretch Marks Treatment', 'stretch-marks-removal',
  'Stretch Marks Treatment at Uncover', 'Microneedling, RF microneedling, and fractional laser', 'Dermatologist-led stretch marks treatment combining microneedling, RF microneedling, and fractional laser. Starts from ₹10,999 per session. Delhi, Gurgaon, Noida.',
  'Abdomen, thighs, hips, breasts, upper arms', '45–60 minutes', '₹10,999',
  '4–8 typical', '1–3 days',
  'Stretch Marks Removal Treatment in Delhi NCR | Uncover', 'Stretch marks treatment at Uncover — microneedling, RF microneedling, fractional laser. Starting ₹10,999. Dermatologist-led across 8 clinics in Delhi NCR.',
  'published', 999, false,
  now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.treatments WHERE slug = 'stretch-marks-removal');

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-stretch-marks-removal-tx-1';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-stretch-marks-removal-tx-1', (SELECT id FROM cms.treatments WHERE slug='stretch-marks-removal'), 1, 'pageBlocks', 'Can Stretch Marks Actually Be Removed?', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Honest answer: stretch marks can be significantly faded — to the point of being cosmetically invisible in many cases — but rarely 100% removed. The treatments work by remodelling the collagen and elastin under the stretch mark, rebuilding the skin''s structure from the inside. Realistic expectation is 60–80% improvement over a full series.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Newer stretch marks (red or purple, under 12 months old) respond better than older ones (white, silvery). If you''ve just had a stretch mark appear, starting treatment within the first year gives the best results.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-stretch-marks-removal-tx-2';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-stretch-marks-removal-tx-2', (SELECT id FROM cms.treatments WHERE slug='stretch-marks-removal'), 2, 'pageBlocks', 'Treatment Options at Uncover', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "RF Microneedling (Morpheus8 / comparable)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Needles + radiofrequency energy deliver collagen-building stimulation to the deep dermis. Best for moderate stretch marks, especially on the abdomen and thighs. 4–6 sessions, 4–6 weeks apart.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Standard microneedling", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Mechanical stimulation without the RF energy. Good for early-stage (red/purple) stretch marks and lighter cases. Lower cost per session. 6–8 sessions.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Fractional laser", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Fractional CO2 or erbium laser for more established white stretch marks. Works by resurfacing the skin in tiny columns, triggering collagen remodelling. Shorter series, more downtime per session. Requires Fitzpatrick assessment first — we use conservative settings on Indian skin.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-stretch-marks-removal-tx-3';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-stretch-marks-removal-tx-3', (SELECT id FROM cms.treatments WHERE slug='stretch-marks-removal'), 3, 'pageBlocks', 'Cost & Session Plan', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Stretch marks treatment at Uncover starts from ₹10,999 per session for microneedling. RF microneedling is typically 30–50% more. Fractional laser ranges ₹15,000–₹25,000 per session depending on area.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Full treatment plans are packaged after consultation — typical 4–6 session plans run ₹50,000–₹1,25,000 depending on area size and technology selection.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

-- ===== /treatment/dandruff-treatment =====
INSERT INTO cms.treatments (
  name, slug,
  hero_headline, hero_tagline, hero_excerpt,
  details_target_areas, details_service_time, details_starting_price,
  details_sessions, details_downtime,
  meta_title, meta_description,
  _status, display_rank, display_show_in_header,
  created_at, updated_at
)
SELECT
  'Dandruff Treatment', 'dandruff-treatment',
  'Dandruff Treatment by Dermatologist', 'Medical shampoos, HydraFacial Keravive & scalp care', 'Dermatologist-led dandruff treatment — medical shampoos, HydraFacial Keravive scalp therapy, prescription topicals. Persistent dandruff, itchy scalp, scalp psoriasis.',
  'Scalp, hairline, behind ears', '30–60 minutes', '₹4,999',
  'Varies by cause', 'None',
  'Dandruff Treatment by Dermatologist in Delhi NCR | Uncover', 'Dermatologist-led dandruff treatment at Uncover — medical shampoos, HydraFacial Keravive scalp therapy, prescription topicals. Delhi, Gurgaon, Noida.',
  'published', 999, false,
  now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.treatments WHERE slug = 'dandruff-treatment');

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-dandruff-treatment-tx-1';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-dandruff-treatment-tx-1', (SELECT id FROM cms.treatments WHERE slug='dandruff-treatment'), 1, 'pageBlocks', 'Why Over-the-Counter Shampoo Isn''t Always Enough', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Dandruff is a common problem that most people try to handle with anti-dandruff shampoo alone. For mild cases that works. For moderate-to-severe dandruff, persistent itchy scalp, or recurrent flaking despite months of supermarket shampoos — you''re looking at an underlying scalp condition that needs diagnosis.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What looks like ''bad dandruff'' is often seborrhoeic dermatitis, scalp psoriasis, fungal overgrowth, or contact dermatitis from products. Each needs a different plan. A dermatologist can tell them apart in one consultation.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-dandruff-treatment-tx-2';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-dandruff-treatment-tx-2', (SELECT id FROM cms.treatments WHERE slug='dandruff-treatment'), 2, 'pageBlocks', 'Treatment Options at Uncover', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Medical shampoos", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Ketoconazole, piroctone olamine, zinc pyrithione, or salicylic acid depending on the underlying cause. Prescription strengths are significantly more effective than over-the-counter equivalents.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "HydraFacial Keravive scalp therapy", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A 3-step in-clinic scalp treatment: deep cleanse, growth-factor and peptide infusion, take-home daily scalp spray. Works well for persistent dandruff combined with thinning or dull scalp health.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Prescription topicals", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Topical steroids for inflammatory scalp conditions, antifungal solutions for persistent fungal overgrowth, or combination formulas for scalp psoriasis.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h3", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Oral therapy", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "For severe or recurrent cases, oral antifungal or anti-inflammatory medication is added to the topical plan under dermatologist supervision.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

DELETE FROM cms.treatments_blocks_text_section WHERE id = 'seo-phase2-new-dandruff-treatment-tx-3';
INSERT INTO cms.treatments_blocks_text_section (id, _parent_id, _order, _path, heading, content)
VALUES ('seo-phase2-new-dandruff-treatment-tx-3', (SELECT id FROM cms.treatments WHERE slug='dandruff-treatment'), 3, 'pageBlocks', 'What to Expect from Treatment', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most moderate dandruff cases resolve in 4–6 weeks on a structured plan. Persistent cases with an underlying condition (psoriasis, chronic seborrhoeic dermatitis) need longer treatment and ongoing maintenance — there''s no permanent cure, but we can bring flares down to a few mild episodes per year.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Dandruff treatment at Uncover starts from ₹4,999 for a diagnostic consultation + initial prescription plan. HydraFacial Keravive scalp therapy is packaged separately at ₹8,999–₹14,999 per session, usually 3–6 sessions.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb);

COMMIT;
